// Define the TrieNode class
class TrieNode {
  // Define the key property
  key;
  // Define the isEndOfWord property
  isEndOfWord;

  // Initialize the Trie with a root node
  static root = new TrieNode();
}

// Define the insertIntoTrieNode function
function insertIntoTrieNode(key) {
  // Base case to handle null or empty keys
  if (key === null || key === '') {
    return;
  }

  // Recursive approach to insert the key into the Trie
  function recursiveInsert(currentNode, charIndex) {
    // If the current node is null, create a new node
    if (!currentNode) {
      currentNode = new TrieNode();
    }

    // If we've reached the end of the key, mark the node as the end of a word
    if (charIndex === key.length - 1) {
      currentNode.isEndOfWord = true;
    }

    // Recursively call the function for the next character
    recursiveInsert(currentNode, charIndex + 1);

    // Insert the current character into the Trie
    currentNode.key += key[charIndex];
  }

  // Call the recursive function to start inserting the key
  recursiveInsert(TrieNode.root, 0);
}

// Test the function
insertIntoTrieNode('apple');
insertIntoTrieNode('banana');
